<span class="line"><span style="color:#89B4FA;font-style:italic;">    print_labeled</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;count&quot;</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 42</span><span style="color:#9399B2;">);</span></span>
